// Unit 22. Les Connecteurs Logiques
// Advanced connectors and conjunctions

export default {n:22,lang:"fr",srcLang:"en",track:"v2",title:"Les Connecteurs Logiques",sub:"Advanced connectors and conjunctions",icon:"🔗",level:"B1.6",color:"#7B5EE8",lessons:[
  {id:"fre22l1",title:"La Cause",icon:"🔍",xp:15,board:true,steps:[
        {type:"intro",title:"La Cause",desc:"Learn to express cause and reason with advanced connectors beyond basic parce que.",goals:["Use puisque, car, comme for cause","Distinguish formal vs informal cause connectors","Use noun-based cause expressions: en raison de, a cause de, grace a"]},
        {type:"teach",trg:"Puisque",src:"Since / Given that (known reason)",pos:"conj",gender:null,phonetic:"pwee-SKUH",note:"Used when the reason is already known to both speakers. More formal than parce que.",example:"A: Puisque tu es la, aide-moi avec ce projet.\nB: Bien sur! Qu'est-ce que je dois faire?\nA: Tu peux corriger les erreurs dans ce texte?\nB: D'accord, je commence tout de suite.",exampleSrc:"A: Since you're here, help me with this project.\nB: Of course! What should I do?\nA: Can you correct the errors in this text?\nB: Okay, I'll start right away.",funFact:"Since / given that. Known-reason. Takes indicative."},
        {type:"teach",trg:"Car",src:"For / Because (formal, written)",pos:"conj",gender:null,phonetic:"kar",note:"Literary/written connector. Never starts a sentence. Followed by a full clause.",example:"A: Pourquoi le musee est-il ferme?\nB: Il est ferme car il y a des renovations.\nA: C'est dommage. Et la galerie?\nB: La galerie reste ouverte car les travaux ne la concernent pas.",exampleSrc:"A: Why is the museum closed?\nB: It's closed because there are renovations.\nA: That's a shame. And the gallery?\nB: The gallery stays open because the work doesn't affect it.",funFact:"For / because (formal, written). Never starts a sentence. Takes indicative."},
        {type:"teach",trg:"Comme",src:"As / Since (cause at start of sentence)",pos:"conj",gender:null,phonetic:"kom",note:"Always at the beginning of the sentence. Expresses a cause that is obvious or already established.",example:"A: Comme il pleut, on reste a la maison?\nB: Oui, bonne idee. On peut regarder un film.\nA: Comme tu as choisi la derniere fois, c'est mon tour.\nB: D'accord, choisis ce que tu veux!",exampleSrc:"A: Since it's raining, shall we stay home?\nB: Yes, good idea. We can watch a film.\nA: Since you chose last time, it's my turn.\nB: Okay, choose whatever you want!",funFact:"As / since (cause). Sentence-initial causal. Takes indicative."},
        {type:"teach",trg:"En raison de",src:"Due to / On account of",pos:"prep",gender:null,phonetic:"on ray-ZON duh",note:"Formal. Followed by a noun, not a clause. Common in announcements and official language.",example:"A: Le vol est annule en raison de la tempete.\nB: Quand est le prochain vol?\nA: En raison de la situation, tous les vols sont retardes.\nB: Il faut trouver un hotel alors.",exampleSrc:"A: The flight is cancelled due to the storm.\nB: When is the next flight?\nA: Due to the situation, all flights are delayed.\nB: We need to find a hotel then.",funFact:"Due to / on account of. Formal causal phrase. En + raison (reason) + de."},
        {type:"teach",trg:"A cause de",src:"Because of (often negative cause)",pos:"prep",gender:null,phonetic:"ah kohz duh",note:"Followed by a noun. Often implies a negative cause. Compare with grace a for positive causes.",example:"A: Je suis en retard a cause de la circulation.\nB: Ce n'est pas grave. La reunion n'a pas encore commence.\nA: A cause de la greve, le metro ne fonctionnait pas.\nB: Oui, beaucoup de gens sont en retard aujourd'hui.",exampleSrc:"A: I'm late because of the traffic.\nB: It's no big deal. The meeting hasn't started yet.\nA: Because of the strike, the metro wasn't working.\nB: Yes, many people are late today.",funFact:"Because of (often negative cause). Contrast with grâce à (positive cause)."},
        {type:"teach",trg:"Grace a",src:"Thanks to (positive cause)",pos:"intj",gender:null,phonetic:"grahs ah",note:"Followed by a noun. Always implies a positive outcome. The opposite of a cause de.",example:"A: Grace a ton aide, j'ai reussi l'examen.\nB: Felicitations! Tu as travaille dur aussi.\nA: Grace a cette methode, j'apprends plus vite.\nB: C'est vrai, elle est vraiment efficace.",exampleSrc:"A: Thanks to your help, I passed the exam.\nB: Congratulations! You worked hard too.\nA: Thanks to this method, I learn faster.\nB: That's true, it's really effective.",funFact:"Thanks to (missing accent should be 'Grâce à'). Gratitude-marker preposition."},
        {type:"tip",title:"Cause connectors: choosing the right one",text:"Clause connectors:\n- parce que: neutral, answers pourquoi\n- puisque: known/obvious reason\n- car: formal/written, never starts a sentence\n- comme: cause at sentence start\n\nNoun connectors:\n- en raison de: formal, neutral\n- a cause de: negative cause\n- grace a: positive cause"},
        {type:"mc",q:"Which connector introduces a cause that is already known to both speakers?",opts:["Puisque","Car","Parce que","En raison de"],ans:"Puisque",hint:"This one assumes shared knowledge between speaker and listener."},
        {type:"fb",opts:["Comme","Car","Puisque","Parce que"],hint:"This cause connector always begins the sentence.",s:"{1} il fait beau, nous allons nous promener.",a:["Comme"]},
        {type:"mc",q:"J'ai rate le bus ___ la circulation.",opts:["grace a","a cause de","en raison de","comme"],ans:"a cause de",hint:"The informal noun connector that implies something negative happened."},
        {type:"fb",opts:["grace a","a cause de","en raison de","malgre"],hint:"The noun connector that indicates a positive outcome from something.",s:"Elle a reussi {1} son travail acharne.",a:["grace a"]},
        {type:"mc",q:"Le magasin est ferme ___ il y a des travaux.",opts:["puisque","comme","car","grace a"],ans:"car",hint:"The literary connector that never starts a sentence."},
        {type:"drag_fill",hint:"First blank: obvious reason at start. Second blank: formal connector mid-sentence.",s:"{1} tu connais la reponse, dis-la-nous. Le professeur sera content {2} tu participes.",blanks:{"1":"Puisque","2":"car"},pool:["Puisque","car","a cause de","grace a"]},
        {type:"fb",opts:["en raison de","grace a","car","puisque"],hint:"The formal noun connector used in official announcements.",s:"Le concert a ete annule {1} la pluie.",a:["en raison de"]},
        {type:"match",pairs:[
          {trg:"Puisque",src:"Since (known reason)"},
          {trg:"Car",src:"For (formal/written)"},
          {trg:"Comme",src:"As (cause, sentence start)"},
          {trg:"A cause de",src:"Because of (negative)"},
          {trg:"Grace a",src:"Thanks to (positive)"}
        ]},
        {type:"mc",q:"___ la greve des transports, les ecoles sont fermees.",opts:["Puisque","Grace a","Car","En raison de"],ans:"En raison de",hint:"A formal noun phrase used in public announcements about disruptions."},
        {type:"fb",opts:["Puisque","Parce que","Car","Comme"],hint:"Implies the listener already knows they registered.",s:"{1} tu es deja inscrit, tu n'as pas besoin de remplir le formulaire.",a:["Puisque"]},
        {type:"mc",q:"Which pair correctly contrasts positive and negative noun-based cause?",opts:["grace a (positive) / a cause de (negative)","en raison de (positive) / car (negative)","comme (positive) / puisque (negative)","car (positive) / parce que (negative)"],ans:"grace a (positive) / a cause de (negative)",hint:"One is for happy outcomes, the other for unfortunate ones. Both take nouns."}
  ]},
  {id:"fre22l2",title:"La Consequence",icon:"➡️",xp:15,board:true,steps:[
        {type:"intro",title:"La Consequence",desc:"Express results and consequences using formal and informal connectors.",goals:["Use donc, alors for informal consequence","Use par consequent, c'est pourquoi for formal consequence","Use si bien que for result clauses"]},
        {type:"teach",trg:"Donc",src:"So / Therefore",pos:"conj",gender:null,phonetic:"donk",note:"The most common consequence connector. Can appear mid-sentence or at the start.",example:"A: Il pleut donc nous restons a l'interieur.\nB: On pourrait jouer aux cartes.\nA: Bonne idee. Tu connais le jeu donc tu peux m'expliquer les regles.\nB: Bien sur, c'est tres simple.",exampleSrc:"A: It's raining so we're staying inside.\nB: We could play cards.\nA: Good idea. You know the game so you can explain the rules.\nB: Of course, it's very simple.",funFact:"So / therefore. Result connector. Takes indicative."},
        {type:"teach",trg:"Alors",src:"So / Then (consequence)",pos:"adv",gender:null,phonetic:"ah-LOR",note:"Informal. Very common in spoken French. Often interchangeable with donc in conversation.",example:"A: Le train est en retard, alors on prend le bus?\nB: Oui, c'est plus rapide alors.\nA: Tu as ton billet, alors?\nB: Oui, je l'ai achete en ligne.",exampleSrc:"A: The train is late, so shall we take the bus?\nB: Yes, that's faster then.\nA: You have your ticket, then?\nB: Yes, I bought it online.",funFact:"So / then (consequence). Native French connector. Discourse marker."},
        {type:"teach",trg:"Par consequent",src:"Consequently / As a result",pos:"intj",gender:null,phonetic:"par kon-say-KON",note:"Very formal. Used in business, academic, and official contexts.",example:"A: Les ventes ont baisse de 20%.\nB: Par consequent, nous devons reduire les couts.\nA: Quelles mesures proposez-vous?\nB: Par consequent, je recommande de geler les embauches.",exampleSrc:"A: Sales have dropped by 20%.\nB: Consequently, we must reduce costs.\nA: What measures do you suggest?\nB: As a result, I recommend freezing hiring.",funFact:"Consequently. Par (by) + conséquent. Formal result-marker."},
        {type:"teach",trg:"C'est pourquoi",src:"That is why / That's why",pos:"intj",gender:null,phonetic:"say poor-KWAH",note:"Links a fact to its logical consequence. Always refers back to what was just said.",example:"A: Marie parle trois langues couramment.\nB: C'est pourquoi elle a obtenu ce poste.\nA: Elle voyage souvent aussi.\nB: Oui, c'est pourquoi son francais est si bon.",exampleSrc:"A: Marie speaks three languages fluently.\nB: That's why she got that position.\nA: She also travels often.\nB: Yes, that's why her French is so good.",funFact:"That's why. Fixed phrase. Result-indicator."},
        {type:"teach",trg:"Si bien que",src:"So much so that / With the result that",pos:"intj",gender:null,phonetic:"see bee-EN kuh",note:"Introduces a strong or notable result. More emphatic than donc. Followed by indicative.",example:"A: Il a neige toute la nuit, si bien que les routes sont bloquees.\nB: On ne peut pas aller au travail alors.\nA: Le chauffage est tombe en panne, si bien que la maison est glaciale.\nB: Appelons un technicien immediatement.",exampleSrc:"A: It snowed all night, so that the roads are blocked.\nB: We can't go to work then.\nA: The heating broke down, so the house is freezing.\nB: Let's call a technician immediately.",funFact:"So much that / so that. Result connector. Takes indicative."},
        {type:"tip",title:"Consequence connectors: register guide",text:"Informal/spoken:\n- donc: most versatile, any register\n- alors: conversational, spontaneous\n\nFormal/written:\n- par consequent: business, academic\n- c'est pourquoi: explains a reason\n- si bien que: emphatic result clause"},
        {type:"mc",q:"Which consequence connector is most appropriate in a business report?",opts:["Par consequent","Alors","Donc","Si bien que"],ans:"Par consequent",hint:"The most formal option, common in professional and academic writing."},
        {type:"fb",opts:["donc","par consequent","c'est pourquoi","si bien que"],hint:"The most common and versatile result connector in everyday speech.",s:"Il fait froid, {1} je mets mon manteau.",a:["donc"]},
        {type:"mc",q:"Elle travaille beaucoup, ___ elle est toujours fatiguee.",opts:["par consequent","si bien que","grace a","en raison de"],ans:"si bien que",hint:"The emphatic connector introducing a strong or notable result."},
        {type:"fb",opts:["alors","par consequent","si bien que","c'est pourquoi"],hint:"The casual spoken connector for a spontaneous consequence.",s:"Le restaurant etait complet, {1} nous sommes alles ailleurs.",a:["alors"]},
        {type:"mc",q:"J'adore la nature. ___ je passe mes vacances a la campagne.",opts:["Alors","Si bien que","C'est pourquoi","Par consequent"],ans:"C'est pourquoi",hint:"The connector that explains why something follows from a stated fact."},
        {type:"drag_fill",hint:"First: emphatic result of heavy rain. Second: formal consequence for planning.",s:"Il a plu toute la semaine, {1} le match a ete annule. {2}, l'equipe s'entrainera en salle.",blanks:{"1":"si bien que","2":"Par consequent"},pool:["si bien que","Par consequent","alors","grace a"]},
        {type:"match",pairs:[{trg:"Donc",src:"So / Therefore"},{trg:"Alors",src:"So / Then (spoken)"},{trg:"Par consequent",src:"Consequently"},{trg:"C'est pourquoi",src:"That is why"},{trg:"Si bien que",src:"So much so that"}]},
        {type:"fb",opts:["C'est pourquoi","Si bien que","Par consequent","Alors"],hint:"Links an observation about someone's ability to a logical recommendation.",s:"Tu parles bien francais. {1} tu devrais passer l'examen.",a:["C'est pourquoi"]},
        {type:"mc",q:"Les prix ont augmente, ___ les clients achetent moins.",opts:["comme","grace a","a cause de","si bien que"],ans:"si bien que",hint:"Shows an emphatic result, not a cause. Followed by indicative mood."},
        {type:"fb",opts:["si bien que","parce que","bien que","pour que"],hint:"A conse___nce connector meaning 'so much so that' with two words.",s:"Il pleuvait fort, {1} nous sommes restes a la maison.",a:["si bien que"]},
        {type:"drag_fill",hint:"First: simple everyday result. Second: explains the reason for her happiness.",s:"Marie est malade, {1} elle reste au lit. {2} elle a reussi, elle est contente.",blanks:{"1":"donc","2":"C'est pourquoi"},pool:["donc","C'est pourquoi","a cause de","malgre"]}
  ]},
  {id:"fre22l3",title:"L'Opposition et la Concession",icon:"⚖️",xp:15,board:true,steps:[
        {type:"intro",title:"L'Opposition et la Concession",desc:"Express contrast and concession: acknowledging one thing while stating another.",goals:["Use cependant, pourtant for formal contrast","Use bien que + subjunctive for concession","Use malgre and en depit de with nouns"]},
        {type:"teach",trg:"Cependant",src:"However / Nevertheless",pos:"conj",gender:null,phonetic:"suh-pon-DON",note:"Formal written connector. Can appear at start of sentence or mid-sentence.",example:"A: Ce restaurant a de bonnes critiques.\nB: Cependant, les prix sont assez eleves.\nA: C'est vrai. La qualite est excellente, cependant.\nB: Oui, on y va pour les grandes occasions.",exampleSrc:"A: This restaurant has good reviews.\nB: However, the prices are quite high.\nA: That's true. The quality is excellent, however.\nB: Yes, we go there for special occasions.",funFact:"However / nevertheless. Contrast. Takes indicative."},
        {type:"teach",trg:"Pourtant",src:"Yet / Nevertheless / Still",pos:"adv",gender:null,phonetic:"poor-TON",note:"Expresses surprise at a contradiction. More emotional than cependant.",example:"A: Il a etudie toute la nuit.\nB: Pourtant, il a rate l'examen.\nA: C'est etrange. Il est intelligent pourtant.\nB: Oui, il etait peut-etre trop fatigue.",exampleSrc:"A: He studied all night.\nB: Yet, he failed the exam.\nA: That's strange. He's intelligent though.\nB: Yes, he was maybe too tired.",funFact:"Yet / nevertheless. Concessive connector. Strong contrast."},
        {type:"teach",trg:"Bien que + subjonctif",src:"Although / Even though",pos:"intj",gender:null,phonetic:"bee-EN kuh",note:"ALWAYS followed by subjunctive. Bien qu' before a vowel. Very common in formal French.",example:"A: Bien qu'il fasse froid, elle sort sans manteau.\nB: Elle est toujours comme ca.\nA: Bien que je sois fatigue, je vais finir ce travail.\nB: Tu es vraiment courageux.",exampleSrc:"A: Although it's cold, she goes out without a coat.\nB: She's always like that.\nA: Although I'm tired, I'm going to finish this work.\nB: You're really brave.",funFact:"Although + subjunctive. Bien que always triggers subjunctive. Concessive."},
        {type:"teach",trg:"Malgre",src:"Despite / In spite of",pos:"verb",gender:null,phonetic:"mal-GRAY",note:"Followed by a noun, never a clause. For a clause, use bien que + subjunctive instead.",example:"A: Malgre la pluie, le festival a eu lieu.\nB: Oui, les gens sont venus quand meme.\nA: Malgre les difficultes, elle a termine son projet.\nB: Elle est tres determinee.",exampleSrc:"A: Despite the rain, the festival took place.\nB: Yes, people came anyway.\nA: Despite the difficulties, she finished her project.\nB: She's very determined.",funFact:"Despite. Missing accent (should be 'malgré'). Concessive preposition."},
        {type:"teach",trg:"En depit de",src:"In spite of / Despite (formal)",pos:"prep",gender:null,phonetic:"on day-PEE duh",note:"Very formal. Same meaning as malgre but used in official or literary contexts. Followed by a noun.",example:"A: En depit de son age, il court un marathon chaque annee.\nB: C'est impressionnant!\nA: En depit des critiques, le film a eu du succes.\nB: Oui, le public l'a beaucoup aime.",exampleSrc:"A: In spite of his age, he runs a marathon every year.\nB: That's impressive!\nA: Despite the criticism, the film was successful.\nB: Yes, the audience loved it.",funFact:"In spite of / despite (formal). Missing accent should be dépit."},
        {type:"tip",title:"Concession: clause vs noun connectors",text:"With a CLAUSE (subject + verb):\n- bien que + subjunctive\n- cependant, pourtant (full sentence)\n\nWith a NOUN:\n- malgre + noun\n- en depit de + noun\n\nRemember: malgre que is considered incorrect by many. Use bien que instead."},
        {type:"mc",q:"Which connector MUST be followed by the subjunctive?",opts:["Bien que","Cependant","Malgre","Pourtant"],ans:"Bien que",hint:"The clause-based concession connector that requires a special verb mood."},
        {type:"fb",opts:["Malgre","Bien que","Pourtant","Cependant"],hint:"The noun-based concession word meaning despite. Takes a noun, not a clause.",s:"{1} les problemes, nous avons reussi.",a:["Malgre"]},
        {type:"mc",q:"Il est riche. ___, il n'est pas heureux.",opts:["Malgre","Pourtant","Bien que","En depit de"],ans:"Pourtant",hint:"Expresses surprise at a contradiction. Stands alone between two sentences."},
        {type:"fb",opts:["Bien qu'","Malgre","Pourtant","Cependant"],hint:"The clause connector requiring subjunctive. Shortened before a vowel.",s:"{1} elle soit malade, elle va travailler.",a:["Bien qu'"]},
        {type:"drag_fill",hint:"First: noun-based concession before a noun. Second: formal contrast connector.",s:"{1} la chaleur, ils jouent dehors. Le parc est bruyant, {2} il reste agreable.",blanks:{"1":"Malgre","2":"cependant"},pool:["Malgre","cependant","bien que","grace a"]},
        {type:"mc",q:"___ des difficultes financieres, l'entreprise a survecu.",opts:["Cependant","Pourtant","En depit","Bien que"],ans:"En depit",hint:"The very formal noun connector, followed by de + noun."},
        {type:"match",pairs:[{trg:"Cependant",src:"However"},{trg:"Pourtant",src:"Yet / Still"},{trg:"Bien que",src:"Although (+subj)"},{trg:"Malgre",src:"Despite (+noun)"},{trg:"En depit de",src:"In spite of (formal)"}]},
        {type:"fb",opts:["cependant","malgre","bien que","en depit de"],hint:"A formal contrast word placed mid-sentence meaning nevertheless.",s:"Le film est long. Il est {1} captivant.",a:["cependant"]},
        {type:"mc",q:"'___ la pluie, ils sont sortis.' Which concession word fits?",opts:["Bien que","Pourtant","Cependant","Malgre"],ans:"Malgre",hint:"Before a noun (la pluie), use the preposition form, not the conjunction."},
        {type:"mc",q:"Malgre ___, elle a gagne la course.",opts:["sa blessure","qu'elle soit blessee","elle est blessee","etre blessee"],ans:"sa blessure",hint:"This connector takes a noun phrase, not a verb clause."},
        {type:"drag_fill",hint:"First: clause connector with subjunctive. Second: noun connector before a noun.",s:"{1} il pleuve, le match continue. {2} les conditions, les joueurs restent motives.",blanks:{"1":"Bien qu'","2":"Malgre"},pool:["Bien qu'","Malgre","Pourtant","Donc"]}
  ]},
  {id:"fre22l4",title:"Le But",icon:"🎯",xp:15,board:true,steps:[
        {type:"intro",title:"Le But",desc:"Express purpose and goals using connectors that require subjunctive or infinitive.",goals:["Use pour que + subjunctive and afin que + subjunctive","Use pour + infinitif and afin de + infinitif","Choose between subjunctive and infinitive purpose clauses"]},
        {type:"teach",trg:"Pour que + subjonctif",src:"So that / In order that",pos:"intj",gender:null,phonetic:"poor kuh",note:"Used when subject of main clause differs from subject of purpose clause. ALWAYS takes subjunctive.",example:"A: Je parle lentement pour que tu comprennes.\nB: Merci, c'est plus facile comme ca.\nA: J'ecris des notes pour que tout le monde soit informe.\nB: C'est une bonne idee, merci.",exampleSrc:"A: I speak slowly so that you understand.\nB: Thank you, it's easier that way.\nA: I write notes so that everyone is informed.\nB: That's a good idea, thanks.",funFact:"In order that + subjunctive. Purpose clause. Subjunctive mandatory."},
        {type:"teach",trg:"Afin que + subjonctif",src:"In order that / So that (formal)",pos:"intj",gender:null,phonetic:"ah-FEN kuh",note:"Formal equivalent of pour que. Same grammar: always + subjunctive. Common in professional writing.",example:"A: Le directeur a organise une reunion afin que tous soient informes.\nB: C'est une bonne initiative.\nA: Il envoie un rapport afin que nous puissions nous preparer.\nB: Parfait, je le lirai ce soir.",exampleSrc:"A: The director organized a meeting so that everyone is informed.\nB: That's a good initiative.\nA: He sends a report so that we can prepare.\nB: Perfect, I'll read it tonight.",funFact:"So that + subjunctive. More formal than 'pour que.' Same purpose meaning."},
        {type:"teach",trg:"Pour + infinitif",src:"In order to / To",pos:"intj",gender:null,phonetic:"poor",note:"Used when SAME subject does both actions. Simpler than pour que. No subjunctive needed.",example:"A: J'etudie le francais pour voyager en France.\nB: C'est une excellente motivation!\nA: Je me leve tot pour avoir le temps de courir.\nB: Tu es vraiment discipline.",exampleSrc:"A: I study French to travel in France.\nB: That's an excellent motivation!\nA: I get up early to have time to run.\nB: You're really disciplined.",funFact:"In order to + infinitive. Used when subjects match. Simpler than 'pour que.'"},
        {type:"teach",trg:"Afin de + infinitif",src:"In order to (formal)",pos:"verb",gender:null,phonetic:"ah-FEN duh",note:"Formal version of pour + infinitif. Same subject for both verbs. Common in professional writing.",example:"A: Elle a pris des cours afin de perfectionner son francais.\nB: C'est admirable.\nA: Nous avons engage un expert afin d'ameliorer nos resultats.\nB: Bonne decision, il est tres competent.",exampleSrc:"A: She took classes in order to perfect her French.\nB: That's admirable.\nA: We hired an expert in order to improve our results.\nB: Good decision, he's very competent.",funFact:"In order to. Formal purpose + infinitive. More formal than pour."},
        {type:"tip",title:"Purpose: subjunctive or infinitive?",text:"Same subject = infinitive:\n- Je travaille pour reussir.\n- Il etudie afin de progresser.\n\nDifferent subjects = subjunctive:\n- Je travaille pour que tu reussisses.\n- Il explique afin que nous comprenions.\n\nKey: if the person doing and benefiting are the same, use infinitive. If different, use subjunctive."},
        {type:"mc",q:"Je parle fort ___ tout le monde entende.",opts:["pour que","pour","afin de","car"],ans:"pour que",hint:"Two different subjects (I speak, everyone hears) require the subjunctive connector."},
        {type:"fb",opts:["pour","pour que","afin que","car"],hint:"Same subject for both verbs, so use the simple infinitive connector.",s:"Elle etudie {1} reussir son examen.",a:["pour"]},
        {type:"mc",q:"Le professeur repete ___ les etudiants comprennent.",opts:["afin de","afin que","pour","donc"],ans:"afin que",hint:"Different subjects (teacher repeats, students understand) need the formal subjunctive connector."},
        {type:"fb",opts:["afin de","afin que","pour que","si bien que"],hint:"Same subject, formal register. The elegant infinitive purpose connector.",s:"Nous travaillons dur {1} terminer a temps.",a:["afin de"]},
        {type:"drag_fill",hint:"First: different subjects need subjunctive. Second: same subject uses infinitive.",s:"Il ecrit un message {1} elle soit au courant. Elle lit le message {2} comprendre la situation.",blanks:{"1":"pour que","2":"pour"},pool:["pour que","pour","afin de","donc"]},
        {type:"mc",q:"Which sentence is grammatically correct?",opts:["Je mange pour que j'aie de l'energie.","Je mange afin que j'ai de l'energie.","Je mange pour avoir de l'energie.","Je mange pour que avoir de l'energie."],ans:"Je mange pour avoir de l'energie.",hint:"When the same person eats and needs energy, the infinitive form is correct."},
        {type:"match",pairs:[
          {trg:"Pour que + subj",src:"So that (diff. subjects)"},
          {trg:"Afin que + subj",src:"In order that (formal)"},
          {trg:"Pour + infinitif",src:"To / In order to"},
          {trg:"Afin de + infinitif",src:"In order to (formal)"}
        ]},
        {type:"fb",opts:["pour que","pour","afin de","car"],hint:"Director organizes, employees get informed. Two different actors require subjunctive.",s:"Le directeur organise une reunion {1} tous les employes soient informes.",a:["pour que"]},
        {type:"mc",q:"Nous avons installe des cameras ___ surveiller le batiment.",opts:["si bien que","afin que","pour que","afin de"],ans:"afin de",hint:"Same entity installs and monitors. Formal register, infinitive construction."},
        {type:"fb",opts:["pour que","parce que","bien que","si bien que"],hint:"A purpose conjunction requiring the subjunctive mood after it.",s:"Je parle lentement {1} tu comprennes.",a:["pour que"]},
        {type:"mc",q:"Which is correct: 'Elle etudie ___ reussir.'",opts:["pour","pour que","afin que","bien que"],ans:"pour",hint:"Before an infinitive (same subject), use the simple preposition form."},
        {type:"drag_fill",hint:"First: she learns and she works (same subject). Second: company pays, she progresses (different).",s:"Elle apprend le francais {1} travailler a Paris. Son entreprise paie les cours {2} elle progresse rapidement.",blanks:{"1":"pour","2":"pour que"},pool:["pour","pour que","afin de","donc"]}
  ]},
  {id:"fre22l5",title:"La Condition",icon:"❓",xp:15,board:true,steps:[
        {type:"intro",title:"La Condition",desc:"Express conditions beyond basic si clauses, using subjunctive condition connectors.",goals:["Use a condition que, pourvu que, a moins que + subjunctive","Distinguish conditional nuances","Combine conditions with other connectors"]},
        {type:"teach",trg:"A condition que + subjonctif",src:"On the condition that / Provided that",pos:"intj",gender:null,phonetic:"ah kon-dee-SYON kuh",note:"Sets a specific requirement. Always + subjunctive. More restrictive than si.",example:"A: Tu peux sortir a condition que tu finisses tes devoirs.\nB: D'accord, je les fais tout de suite.\nA: Je te prete ma voiture a condition que tu sois prudent.\nB: Promis, je ferai tres attention.",exampleSrc:"A: You can go out on the condition that you finish your homework.\nB: Okay, I'll do them right away.\nA: I'll lend you my car provided that you're careful.\nB: I promise, I'll be very careful.",funFact:"Provided that + subjunctive. Conditional connector."},
        {type:"teach",trg:"Pourvu que + subjonctif",src:"Provided that / As long as",pos:"intj",gender:null,phonetic:"poor-VU kuh",note:"Can express a hopeful wish (Pourvu que...!) or a condition (as long as). Always + subjunctive.",example:"A: Pourvu qu'il fasse beau demain!\nB: Oui, on a besoin de soleil pour le pique-nique.\nA: Je suis d'accord, pourvu que tout le monde participe.\nB: Ne t'inquiete pas, tout le monde a confirme.",exampleSrc:"A: If only the weather is nice tomorrow!\nB: Yes, we need sunshine for the picnic.\nA: I agree, as long as everyone participates.\nB: Don't worry, everyone has confirmed.",funFact:"Provided that / as long as + subjunctive. Similar to à condition que."},
        {type:"teach",trg:"A moins que + subjonctif",src:"Unless",pos:"intj",gender:null,phonetic:"ah mwen kuh",note:"Introduces an exception to the main statement. Always + subjunctive. Often paired with ne expletif.",example:"A: Nous partons a huit heures, a moins qu'il pleuve.\nB: D'accord. Et s'il pleut?\nA: On reporte a demain, a moins que tu preferes rester ici.\nB: Non, je veux vraiment y aller.",exampleSrc:"A: We leave at eight, unless it rains.\nB: Okay. And if it rains?\nA: We postpone to tomorrow, unless you prefer to stay here.\nB: No, I really want to go.",funFact:"Unless + subjunctive. Negative conditional. Requires 'ne' expletive in formal French."},
        {type:"tip",title:"Condition connectors: si vs subjunctive",text:"si + indicative: general condition\n- Si tu viens, je suis content.\n\na condition que + subj: specific requirement\n- Tu peux venir a condition que tu sois calme.\n\npourvu que + subj: hopeful / as long as\n- Pourvu qu'il fasse beau!\n\na moins que + subj: exception (unless)\n- Je viens a moins qu'il pleuve.\n\nAll three subjunctive connectors express uncertainty about whether the condition will be met."},
        {type:"mc",q:"Tu peux emprunter mon livre ___ tu le rendes demain.",opts:["a condition que","a moins que","pourvu que","si bien que"],ans:"a condition que",hint:"Setting a specific requirement for lending: the book must come back."},
        {type:"fb",opts:["Pourvu qu'","A condition qu'","A moins qu'","Si"],hint:"A hopeful wish about the weather. Expresses a desire, not a requirement.",s:"{1} il fasse beau ce week-end!",a:["Pourvu qu'"]},
        {type:"mc",q:"Je viendrai a ta fete, ___ je sois malade.",opts:["a condition que","a moins que","pourvu que","par consequent"],ans:"a moins que",hint:"Introduces the one exception that would prevent attendance."},
        {type:"fb",opts:["a condition que","a moins que","pourvu que","bien que"],hint:"Your boss sets a requirement: finish the work first, then you may leave.",s:"Vous pouvez partir tot {1} votre travail soit termine.",a:["a condition que"]},
        {type:"drag_fill",hint:"First: states the exception (rain). Second: expresses a hopeful wish.",s:"On fait le pique-nique demain, {1} il ne pleuve pas. {2} tout le monde vienne!",blanks:{"1":"a moins qu'","2":"Pourvu que"},pool:["a moins qu'","Pourvu que","A condition que","Si bien que"]},
        {type:"mc",q:"Which connector expresses both a wish AND a condition?",opts:["A condition que","A moins que","Pourvu que","Si"],ans:"Pourvu que",hint:"Can mean as long as (condition) or if only (wish). Dual function connector."},
        {type:"fb",opts:["pourvu que","parce que","puisque","pendant que"],hint:"A formal condition word meaning 'provided that' requiring subjunctive.",s:"Tu peux sortir {1} tu finisses tes devoirs.",a:["pourvu que"]},
        {type:"mc",q:"'___ qu'il pleuve, nous irons au parc.' means 'Unless it rains...'",opts:["Pour","A condition","Pourvu","A moins"],ans:"A moins",hint:"The condition word meaning 'unless' starts with the preposition for 'at'."},
        {type:"fb",opts:["a condition que","a moins que","pourvu que","pour que"],hint:"'On the ___ that' everything is ready. Three-word conjunction.",s:"Nous partirons a l'heure {1} tout soit pret.",a:["a condition que"]},
        {type:"match",pairs:[{trg:"A condition que",src:"On the condition that"},{trg:"Pourvu que",src:"Provided that / If only"},{trg:"A moins que",src:"Unless"},{trg:"Si",src:"If (general)"}]},
        {type:"fb",opts:["pourvu que","a moins que","a condition que","malgre que"],hint:"Expresses hope and a soft condition: success depends on teamwork.",s:"Le projet reussira, {1} nous travaillions ensemble.",a:["pourvu que"]},
        {type:"mc",q:"___ vous ayez une reservation, vous ne pourrez pas entrer.",opts:["A moins que","A condition que","Pourvu que","Bien que"],ans:"A moins que",hint:"Without a reservation, no entry. This connector introduces the exception."},
        {type:"drag_fill",hint:"First: a parent's requirement. Second: a hopeful wish about weather.",s:"Tu peux jouer dehors {1} tu mettes ton manteau. Nous sortons {2} la pluie s'arrete.",blanks:{"1":"a condition que","2":"pourvu que"},pool:["a condition que","pourvu que","a moins que","car"]}
  ]},
  {id:"fre22l6",title:"La Comparaison",icon:"📊",xp:15,board:true,steps:[
        {type:"intro",title:"La Comparaison",desc:"Express comparison, similarity, and contrast between ideas and situations.",goals:["Use comme, de meme que for similarity","Use tandis que, alors que for contrast","Use autant que for equal comparison"]},
        {type:"teach",trg:"Comme",src:"Like / As (comparison)",pos:"conj",gender:null,phonetic:"kom",note:"Most common comparison word. Also used for cause (see L1), but here it means like or as.",example:"A: Elle chante comme une professionnelle.\nB: C'est vrai, elle a beaucoup de talent.\nA: Comme toi, j'adore la musique classique.\nB: On devrait aller a un concert ensemble!",exampleSrc:"A: She sings like a professional.\nB: That's true, she has a lot of talent.\nA: Like you, I love classical music.\nB: We should go to a concert together!",funFact:"As / since (cause). Sentence-initial causal. Takes indicative."},
        {type:"teach",trg:"De meme que",src:"Just as / In the same way as",pos:"prep",gender:null,phonetic:"duh mem kuh",note:"Formal comparison. Draws a parallel between two similar things. Common in essays and formal speech.",example:"A: De meme que le francais, l'espagnol est une langue romane.\nB: Oui, elles ont beaucoup de points communs.\nA: De meme que son pere, elle est devenue medecin.\nB: C'est une vraie tradition familiale.",exampleSrc:"A: Just as French, Spanish is a Romance language.\nB: Yes, they have a lot in common.\nA: Just as her father, she became a doctor.\nB: It's a real family tradition.",funFact:"Just as / in the same way as. Missing accent 'même.' Similarity marker."},
        {type:"teach",trg:"Tandis que",src:"While / Whereas",pos:"intj",gender:null,phonetic:"ton-DEE kuh",note:"Expresses contrast between two simultaneous facts. Neutral tone, not adversarial.",example:"A: Pierre aime le cinema, tandis que Marie prefere le theatre.\nB: Ils sont vraiment differents.\nA: Tandis que le nord est froid, le sud est ensoleille.\nB: C'est pourquoi je prefere vivre dans le sud.",exampleSrc:"A: Pierre likes cinema, whereas Marie prefers theatre.\nB: They're really different.\nA: While the north is cold, the south is sunny.\nB: That's why I prefer living in the south.",funFact:"Whereas / while. Contrast connector. Takes indicative."},
        {type:"teach",trg:"Alors que",src:"While / Whereas (unexpected contrast)",pos:"intj",gender:null,phonetic:"ah-LOR kuh",note:"Similar to tandis que but often implies surprise or unexpectedness. Also used for time contrast.",example:"A: Il dort tranquillement alors que la maison est en desordre.\nB: C'est typique de lui.\nA: Elle sourit alors qu'elle est triste.\nB: Elle ne veut pas inquieter ses amis.",exampleSrc:"A: He sleeps peacefully while the house is a mess.\nB: That's typical of him.\nA: She smiles whereas she's sad.\nB: She doesn't want to worry her friends.",funFact:"Whereas / while (contrast). Duplicates tandis que. Context varies."},
        {type:"teach",trg:"Autant que",src:"As much as",pos:"intj",gender:null,phonetic:"oh-TON kuh",note:"Expresses equal degree. For unequal: plus que (more than), moins que (less than).",example:"A: J'aime le chocolat autant que toi.\nB: Impossible, personne n'aime le chocolat autant que moi!\nA: Elle travaille autant que ses collegues.\nB: Oui, elle merite une promotion.",exampleSrc:"A: I like chocolate as much as you.\nB: Impossible, nobody likes chocolate as much as me!\nA: She works as much as her colleagues.\nB: Yes, she deserves a promotion.",funFact:"As much as. Comparison. Takes indicative or subjunctive."},
        {type:"tip",title:"Comparison vs contrast connectors",text:"Similarity:\n- comme: like, as (informal)\n- de meme que: just as (formal)\n- autant que: as much as\n\nContrast:\n- tandis que: neutral contrast\n- alors que: surprising contrast\n\nRemember: tandis que and alors que are very close in meaning. Alors que adds a note of surprise."},
        {type:"mc",q:"Pierre est grand, ___ son frere est petit.",opts:["tandis que","comme","autant que","de meme que"],ans:"tandis que",hint:"A neutral connector showing two contrasting facts side by side."},
        {type:"fb",opts:["comme","tandis que","alors que","de meme que"],hint:"The everyday word for comparing someone to something. Means like or as.",s:"Elle travaille {1} une acharnee.",a:["comme"]},
        {type:"mc",q:"Il rit ___ la situation est grave.",opts:["comme","alors que","autant que","de meme que"],ans:"alors que",hint:"His laughter is unexpected given the serious situation. Implies surprise."},
        {type:"fb",opts:["De meme que","Tandis que","Alors que","Comme"],hint:"The formal comparison drawing a parallel between two similar activities.",s:"{1} le sport, la musique demande de la discipline.",a:["De meme que"]},
        {type:"drag_fill",hint:"First: comparison (like a star). Second: contrast between siblings.",s:"Marie chante {1} une star, {2} son frere ne sait pas chanter du tout.",blanks:{"1":"comme","2":"tandis que"},pool:["comme","tandis que","autant que","de meme que"]},
        {type:"mc",q:"J'aime le cafe ___ le the.",opts:["alors que","tandis que","autant que","de meme que"],ans:"autant que",hint:"Expresses equal liking for both beverages. Neither more nor less."},
        {type:"match",pairs:[{trg:"Comme",src:"Like / As"},{trg:"De meme que",src:"Just as (formal)"},{trg:"Tandis que",src:"While / Whereas"},{trg:"Alors que",src:"Whereas (surprise)"},{trg:"Autant que",src:"As much as"}]},
        {type:"fb",opts:["tandis que","comme","autant que","de meme que"],hint:"Neutral contrast between two animals doing different things simultaneously.",s:"Le chat dort {1} le chien joue dans le jardin.",a:["tandis que"]},
        {type:"fb",opts:["tandis que","parce que","pour que","bien que"],hint:"A comparison/contrast word meaning 'while/whereas' showing two actions.",s:"Elle travaille {1} son frere joue.",a:["tandis que"]},
        {type:"mc",q:"'Il est grand, ___ son pere est petit.' Best contrast word?",opts:["si bien que","parce que","pour que","alors que"],ans:"alors que",hint:"A contrast conjunction showing opposing situations between two clauses."},
        {type:"mc",q:"___ son pere, il est devenu avocat.",opts:["De meme que","Tandis que","Alors que","Autant que"],ans:"De meme que",hint:"A formal parallel: father and son followed the same career path."}
  ]},
  {id:"fre22l7",title:"Le Temps et l'Addition",icon:"📋",xp:15,board:true,steps:[
        {type:"intro",title:"Le Temps et l'Addition",desc:"Organize ideas with time sequencers and addition connectors for structured speech and writing.",goals:["Use d'abord, ensuite, puis, enfin for sequences","Use de plus, en outre, d'ailleurs for adding ideas","Structure a logical argument or narrative"]},
        {type:"teach",trg:"D'abord",src:"First / First of all",pos:"adv",gender:null,phonetic:"dah-BOR",note:"Opens a sequence. Signals the first step in a series of actions or arguments.",example:"A: Comment prepares-tu ton voyage?\nB: D'abord, je choisis la destination.\nA: Et ensuite?\nB: D'abord, je reserve l'hotel, puis les billets d'avion.",exampleSrc:"A: How do you prepare your trip?\nB: First, I choose the destination.\nA: And then?\nB: First, I book the hotel, then the plane tickets.",funFact:"First / first of all. Narrative opener. D' elided + abord (approach)."},
        {type:"teach",trg:"Ensuite",src:"Then / Next / After that",pos:"adv",gender:null,phonetic:"on-SWEET",note:"Follows d'abord in a sequence. Can also be used alone to mean after that.",example:"A: D'abord, on visite le musee.\nB: Et ensuite?\nA: Ensuite, on dejeune au restaurant.\nB: Parfait! Et apres le dejeuner?",exampleSrc:"A: First, we visit the museum.\nB: And then?\nA: Next, we have lunch at the restaurant.\nB: Perfect! And after lunch?",funFact:"Then / next. Sequential connector. Narrative ordering."},
        {type:"teach",trg:"Puis",src:"Then / And then",pos:"adv",gender:null,phonetic:"pwee",note:"Shorter and more conversational than ensuite. Common in everyday narratives.",example:"A: Je me leve, puis je prends une douche.\nB: Tu prends le petit-dejeuner apres?\nA: Oui, puis je pars au travail.\nB: Ta routine est tres organisee.",exampleSrc:"A: I get up, then I take a shower.\nB: Do you have breakfast after?\nA: Yes, then I leave for work.\nB: Your routine is very organized.",funFact:"Then / and then. Shorter than ensuite. Casual sequential."},
        {type:"teach",trg:"Enfin",src:"Finally / Lastly",pos:"adv",gender:null,phonetic:"on-FEN",note:"Closes a sequence. Can also express relief or impatience (Enfin! = At last!).",example:"A: D'abord le cours de maths, ensuite le francais.\nB: Et apres?\nA: Puis l'histoire, et enfin la recreation!\nB: Enfin! La recreation est le meilleur moment.",exampleSrc:"A: First the math class, then French.\nB: And after?\nA: Then history, and finally break time!\nB: Finally! Break time is the best moment.",funFact:"Finally / lastly. From en + fin (end). Literally 'in end.' Narrative closer."},
        {type:"teach",trg:"De plus",src:"Moreover / Furthermore",pos:"adv",gender:null,phonetic:"duh plu",note:"Adds a supporting argument. Common in both spoken and written French.",example:"A: Ce restaurant est delicieux.\nB: De plus, les prix sont raisonnables.\nA: De plus, le service est excellent.\nB: On y retourne la semaine prochaine?",exampleSrc:"A: This restaurant is delicious.\nB: Moreover, the prices are reasonable.\nA: Furthermore, the service is excellent.\nB: Shall we go back next week?",funFact:"Moreover / furthermore. De + plus (more). Additive connector."},
        {type:"teach",trg:"En outre",src:"Furthermore / In addition (formal)",pos:"intj",gender:null,phonetic:"on OOT-ruh",note:"Very formal. Used in business, academic, and official contexts. Stronger than de plus.",example:"A: Le candidat a une excellente formation.\nB: En outre, il a cinq ans d'experience.\nA: En outre, il parle trois langues.\nB: Il est parfait pour le poste.",exampleSrc:"A: The candidate has excellent training.\nB: In addition, he has five years of experience.\nA: Furthermore, he speaks three languages.\nB: He's perfect for the position.",funFact:"Moreover / furthermore. Formal additive connector."},
        {type:"teach",trg:"D'ailleurs",src:"Besides / Moreover / By the way",pos:"adv",gender:null,phonetic:"dah-YEUR",note:"Adds a related thought or reinforcing argument. Can mean by the way in conversation.",example:"A: Je ne veux pas sortir ce soir.\nB: Moi non plus, d'ailleurs.\nA: D'ailleurs, il fait trop froid dehors.\nB: Restons a la maison alors.",exampleSrc:"A: I don't want to go out tonight.\nB: Me neither, actually.\nA: Besides, it's too cold outside.\nB: Let's stay home then.",funFact:"Besides / by the way. Topic-shift marker. D' + ailleurs (elsewhere). Literally 'from elsewhere.'"},
        {type:"tip",title:"Sequencing and adding: organization tools",text:"Time sequence:\nd'abord > ensuite > puis > enfin\n\nAdding arguments:\n- de plus: general addition\n- en outre: formal addition\n- d'ailleurs: related addition, sometimes conversational\n\nUse these to structure essays, presentations, and even daily narratives."},
        {type:"mc",q:"Which word closes a sequence as the final step?",opts:["Enfin","D'abord","Ensuite","Puis"],ans:"Enfin",hint:"The word that signals you have reached the last item in a series."},
        {type:"fb",opts:["De plus","D'abord","Enfin","Puis"],hint:"Adds a second criticism on top of the first one. A reinforcing connector.",s:"Ce film est ennuyeux. {1}, il est trop long.",a:["De plus"]},
        {type:"mc",q:"Le projet est innovant. ___, il respecte le budget.",opts:["Enfin","En outre","Puis","D'abord"],ans:"En outre",hint:"Adds a formal supporting point in a professional context."},
        {type:"drag_fill",hint:"The word that opens a sequence as the very first step.",s:"{1}, je lis les instructions. {2}, je commence le travail.",blanks:{"1":"D'abord"},pool:["D'abord","Ensuite","Puis","Enfin"]},
        {type:"drag_fill",hint:"A recipe sequence: first, next, then. Three steps in order.",s:"{1}, melangez les ingredients. {2}, versez dans le moule. {3}, mettez au four.",blanks:{"1":"D'abord","2":"Ensuite","3":"Puis"},pool:["D'abord","Ensuite","Puis","En outre"]},
        {type:"match",pairs:[{trg:"D'abord",src:"First"},{trg:"Ensuite",src:"Then / Next"},{trg:"Puis",src:"Then (casual)"},{trg:"Enfin",src:"Finally"},{trg:"De plus",src:"Moreover"},{trg:"En outre",src:"Furthermore"}]},
        {type:"mc",q:"Je ne peux pas venir. ___, j'ai deja un rendez-vous.",opts:["Enfin","En outre","D'ailleurs","Ensuite"],ans:"D'ailleurs",hint:"Adds a related, reinforcing reason in a conversational tone."},
        {type:"fb",opts:["De plus","D'abord","Puis","Enfin"],hint:"Reinforces a positive assessment with an additional quality.",s:"Le candidat est competent. {1}, il est tres motive.",a:["De plus"]},
        {type:"drag_fill",hint:"A travel itinerary: first city, second city, final destination.",s:"{1}, nous visitons Paris. {2}, nous allons a Lyon. {3}, nous terminons a Nice.",blanks:{"1":"D'abord","2":"Ensuite","3":"Enfin"},pool:["D'abord","Ensuite","Enfin","De plus"]}
  ]},
  {id:"fre22l8",title:"Revision: Tous les Connecteurs",icon:"🏆",xp:15,board:true,steps:[
        {type:"intro",title:"Revision: Tous les Connecteurs",desc:"Comprehensive review combining all connector categories from this unit.",goals:["Choose the correct connector category for each context","Distinguish register (formal vs informal)","Combine multiple connectors in extended texts"]},
        {type:"mc",q:"Choose the correct cause connector: ___ il pleut, le match est annule.",opts:["Comme","Car","Donc","Pourtant"],ans:"Comme",hint:"A cause connector that always starts the sentence, introducing an obvious fact."},
        {type:"fb",opts:["en raison de","grace a","si bien que","pourtant"],hint:"A formal noun-based cause connector used in travel announcements.",s:"Le vol est retarde {1} le brouillard.",a:["en raison de"]},
        {type:"mc",q:"Il a etudie dur, ___ il a reussi.",opts:["pourtant","donc","malgre","bien que"],ans:"donc",hint:"The universal connector showing a logical result from studying hard."},
        {type:"fb",opts:["Malgre","Grace a","Comme","Donc"],hint:"Playing continues despite an obstacle. Takes a noun, not a clause.",s:"{1} la chaleur, ils continuent de jouer.",a:["Malgre"]},
        {type:"drag_fill",hint:"First: different subjects (she works, children benefit). Second: adds another point. Third: same subject uses infinitive.",s:"Elle travaille dur {1} ses enfants aient une bonne vie. {2}, elle fait du sport {3} rester en forme.",blanks:{"1":"pour que","2":"De plus","3":"pour"},pool:["pour que","De plus","pour","car"]},
        {type:"mc",q:"Tu peux sortir ___ tu aies fini tes devoirs.",opts:["pour que","a moins que","a condition que","tandis que"],ans:"a condition que",hint:"A parent's requirement before allowing something. Sets a ___."},
        {type:"fb",opts:["tandis que","comme","autant que","puisque"],hint:"A neutral contrast between two people's preferences.",s:"Marie aime le the, {1} Pierre prefere le cafe.",a:["tandis que"]},
        {type:"drag_fill",hint:"Three exam instructions in sequence: first, next, last.",s:"{1}, lisez le texte. {2}, repondez aux questions. {3}, verifiez vos reponses.",blanks:{"1":"D'abord","2":"Ensuite","3":"Enfin"},pool:["D'abord","Ensuite","Enfin","De plus"]},
        {type:"mc",q:"___ elle soit fatiguee, elle continue de travailler.",opts:["Cependant","Malgre","Pourtant","Bien qu'"],ans:"Bien qu'",hint:"The clause-based concession connector that requires subjunctive mood."},
        {type:"fb",opts:["De plus","Pourtant","Malgre","Alors que"],hint:"Adding a second positive point to reinforce the first observation.",s:"Le restaurant est excellent. {1}, les prix sont raisonnables.",a:["De plus"]},
        {type:"drag_fill",hint:"First: concession with noun. Second: formal contrast. Third: positive cause with noun.",s:"{1} son experience, il n'a pas obtenu le poste. {2}, un candidat moins qualifie a ete choisi. {3} ses amis, il a trouve un autre emploi rapidement.",blanks:{"1":"Malgre","2":"Cependant","3":"Grace a"},pool:["Malgre","Cependant","Grace a","Puisque"]},
        {type:"mc",q:"Elle a economise de l'argent ___ s'acheter une voiture.",opts:["pour","pour que","afin que","car"],ans:"pour",hint:"Same person saves and buys. Single subject needs the infinitive purpose connector."},
        {type:"match",pairs:[
          {trg:"Puisque",src:"Since (known reason)"},
          {trg:"Si bien que",src:"So much so that"},
          {trg:"Bien que",src:"Although (+subj)"},
          {trg:"A moins que",src:"Unless (+subj)"},
          {trg:"D'ailleurs",src:"Besides / Moreover"},
          {trg:"Tandis que",src:"While / Whereas"}
        ]},
        {type:"fb",opts:["a moins qu'","pourvu qu'","a condition qu'","bien qu'"],hint:"The one exception that would cancel departure. Means unless.",s:"Nous partons demain, {1} il y ait une tempete.",a:["a moins qu'"]},
        {type:"drag_fill",hint:"First: known reason (you're done). Second: formal cause, mid-sentence. Third: positive noun cause.",s:"{1} tu as fini, aide-moi. Le travail est urgent, {2} je ne peux pas le faire seul. {3} ton aide, on terminera a temps.",blanks:{"1":"Puisque","2":"car","3":"Grace a"},pool:["Puisque","car","Grace a","Malgre"]},
        {type:"mc",q:"Il est intelligent ___ il ne travaille pas assez.",opts:["donc","pourtant","puisque","de meme que"],ans:"pourtant",hint:"Surprise at a contradiction: intelligence but insufficient effort."},
        {type:"fb",opts:["De meme que","Tandis que","Alors que","Pourtant"],hint:"Drawing a formal parallel between two languages in the same family.",s:"{1} le francais, l'italien est une langue romane.",a:["De meme que"]},
        {type:"drag_fill",hint:"First: concession with subjunctive. Second: emphatic consequence. Third: adds another point.",s:"{1} il fasse froid, elle sort courir. Elle court tous les jours, {2} elle est en excellente forme. {3}, elle participe a des competitions.",blanks:{"1":"Bien qu'","2":"si bien que","3":"De plus"},pool:["Bien qu'","si bien que","De plus","A cause de"]},
        {type:"mc",q:"Le directeur a envoye un rapport ___ tous les employes puissent se preparer.",opts:["pour","afin de","afin que","donc"],ans:"afin que",hint:"Director sends, employees prepare. Different subjects need the formal subjunctive connector."}
  ]},
  {id:"frv2_u22l_essential_a2_b2",title:"Vocabulaire Essentiel: A2 et Discours Civique",icon:"🌐",xp:20,board:true,steps:[
        {type:"intro",title:"Essential A2 + Civic B2 Vocabulary",desc:"This lesson fills two gaps in one: everyday A2 essentials you will hear every day, and four key civic vocabulary words required for DELF B2 discourse about society and the world.",goals:["Use pas cher, encore, content in everyday conversation","Discuss urgencies and workplace with urgence and collegue","Talk about globalization, democracy, immigration, and inequality at B2 level"]},
        {type:"teach",trg:"pas cher",src:"cheap / not expensive",pos:"adv",gender:null,phonetic:"pah SHAIR",note:"Pas cher = not expensive. Feminine form: pas chere.\nLiteral: not (pas) + expensive (cher).\nOpposite: tres cher (very expensive).",example:"A: C'est cher, ce manteau?\nB: Non, c'est pas cher du tout. Seulement vingt euros.\nA: Vraiment? Je le prends!\nB: Bonne affaire!",exampleSrc:"A: Is this coat expensive?\nB: No, it's not expensive at all. Only twenty euros.\nA: Really? I'll take it!\nB: Great deal!",funFact:"In casual spoken French, 'pas cher' replaces the more formal 'bon marche.' The ne of negation drops in speech: 'c'est pas cher' vs formal 'ce n'est pas cher.'"},
        {type:"teach",trg:"l'urgence",src:"the emergency / urgency",pos:"noun",gender:"f",phonetic:"loor-ZHONCE",note:"Feminine noun. En urgence = urgently, as an emergency.\nC'est une urgence! = It's an emergency!\nLes urgences = the emergency room (hospital).",example:"A: C'est une urgence!\nB: Qu'est-ce qui se passe?\nA: Mon collegue est tombe malade. Il faut l'aider en urgence.\nB: J'appelle l'hopital tout de suite.",exampleSrc:"A: It's an emergency!\nB: What's happening?\nA: My colleague fell ill. We need to help him urgently.\nB: I'll call the hospital right away.",funFact:"Les urgences (plural) is the everyday word for the ER. 'Aux urgences' means 'in the emergency room.' Derived from Latin urgere (to press, to be urgent)."},
        {type:"teach",trg:"le collegue",src:"the colleague (m) / la collegue (f)",pos:"noun",gender:"m",phonetic:"luh ko-LEG",note:"Masculine: le collegue. Feminine: la collegue.\nRefers to someone you work with.\nPlural: les collegues.",example:"A: Tu connais mes collegues?\nB: Oui, je les ai rencontres a la reunion.\nA: Le collegue de Marie est tres competent.\nB: Oui, toute l'equipe travaille bien ensemble.",exampleSrc:"A: Do you know my colleagues?\nB: Yes, I met them at the meeting.\nA: Marie's colleague is very competent.\nB: Yes, the whole team works well together.",funFact:"Collegue comes from Latin collega (co + legare: appointed together). It entered French in the 16th century and is now essential in professional settings."},
        {type:"teach",trg:"encore",src:"again / still / yet",pos:"adv",gender:null,phonetic:"on-KOR",note:"Encore has three main meanings:\n1. Again: Je veux encore du cafe = I want more coffee.\n2. Still: Elle travaille encore = She is still working.\n3. Not yet (with negation): Pas encore = not yet.",example:"A: Tu veux encore du the?\nB: Non merci, j'en ai encore.\nA: Tu as fini le rapport?\nB: Pas encore, je travaille encore dessus.",exampleSrc:"A: Do you want more tea?\nB: No thanks, I still have some.\nA: Have you finished the report?\nB: Not yet, I'm still working on it.",funFact:"Encore is one of French's most versatile adverbs. English borrowed it for concert encores. It comes from Latin hinc ad horam (from here to this hour), meaning 'up to now.'"},
        {type:"teach",trg:"content",src:"happy / pleased (m) / contente (f)",pos:"adj",gender:null,phonetic:"kon-TON / kon-TONT",note:"Content = pleased, happy. Agreement required:\nMasculine: content\nFeminine: contente\nPlural: contents / contentes\nSlightly more formal than heureux.",example:"A: Tu es content de ton nouveau travail?\nB: Oui, je suis tres content! Les collegues sont sympa.\nA: Ta femme est contente aussi?\nB: Oui, elle est tres contente de l'appartement.",exampleSrc:"A: Are you happy with your new job?\nB: Yes, I'm very happy! The colleagues are nice.\nA: Is your wife pleased too?\nB: Yes, she's very pleased with the apartment.",funFact:"Content comes from Latin contentus (satisfied, contained). In Old French it meant 'satisfied with what one has,' suggesting contentment rather than excitement. A satisfied cat is content; a joyful one is heureux."},
        {type:"tip",title:"Encore: three meanings in context",text:"encore + quantity = more/again:\n  Je veux encore du cafe. (I want more coffee.)\n\nstill (present situation):\n  Il travaille encore. (He is still working.)\n\nnot yet (negation):\n  Pas encore. (Not yet.)\n\nTip: context tells you which meaning applies. Look for negation (pas encore) or a quantity noun (encore du/de la)."},
        {type:"teach",trg:"la mondialisation",src:"globalization",pos:"noun",gender:"f",phonetic:"mon-dyah-lee-zah-SYON",note:"Feminine noun. Key term for DELF B2 essays on economics and society.\nMondialisation = the process by which the world becomes increasingly interconnected.",example:"A: Qu'est-ce que tu penses de la mondialisation?\nB: C'est complexe. Elle cree des inegalites, mais aussi des opportunites.\nA: Et pour l'economie?\nB: La mondialisation a transforme le commerce mondial.",exampleSrc:"A: What do you think about globalization?\nB: It's complex. It creates inequalities, but also opportunities.\nA: And for the economy?\nB: Globalization has transformed world trade.",funFact:"The word mondialisation is the standard French term; anglophone media sometimes uses 'globalisation.' Both describe the same process. From monde (world) + -isation (the process of making)."},
        {type:"teach",trg:"la democratie",src:"democracy",pos:"noun",gender:"f",phonetic:"day-mo-kra-SEE",note:"Feminine noun. Key civic vocabulary.\nDemocratique = democratic (adjective).\nUsed in political discourse, history, and B2 argumentative essays.",example:"A: La democratie est-elle en danger?\nB: Certains pensent que oui, a cause de la desinformation.\nA: Et selon toi?\nB: Je crois que la democratie reste le meilleur systeme.",exampleSrc:"A: Is democracy in danger?\nB: Some think so, because of misinformation.\nA: And in your opinion?\nB: I believe democracy remains the best system.",funFact:"From Greek demokratia: demos (people) + kratos (power/rule). The word entered French via Latin in the 16th century. France declared itself a republic (a form of democracy) in 1792."},
        {type:"teach",trg:"l'immigration",src:"immigration",pos:"noun",gender:"f",phonetic:"ee-mee-gra-SYON",note:"Feminine noun. Key civic term.\nImmigration = people moving into a country.\nImmigre / immigree = immigrant.\nDistinct from emigration (leaving a country).",example:"A: L'immigration est un sujet politique important en France.\nB: Oui, il faut trouver un equilibre entre accueil et integration.\nA: La France a toujours eu une forte immigration.\nB: C'est vrai, cela a enrichi la culture francaise.",exampleSrc:"A: Immigration is an important political topic in France.\nB: Yes, a balance between welcome and integration must be found.\nA: France has always had significant immigration.\nB: True, it has enriched French culture.",funFact:"France has had waves of immigration since the 19th century: Italians, Poles, Spaniards, then North Africans and sub-Saharan Africans. The DELF B2 exam regularly features immigration as a discussion topic."},
        {type:"teach",trg:"l'inegalite",src:"inequality",pos:"noun",gender:"f",phonetic:"ee-nay-gah-lee-TAY",note:"Feminine noun. Often used in plural: les inegalites (inequalities).\nInegalite sociale = social inequality.\nCore term for DELF B2 essays on society and justice.",example:"A: Les inegalites sociales augmentent dans de nombreux pays.\nB: C'est un probleme serieux pour la democratie.\nA: Comment lutter contre ces inegalites?\nB: Par une meilleure education et des politiques sociales adaptees.",exampleSrc:"A: Social inequalities are growing in many countries.\nB: It's a serious problem for democracy.\nA: How do we fight these inequalities?\nB: Through better education and appropriate social policies.",funFact:"Inegalite = in- (not) + egalite (equality). The French Revolution's motto Liberte, Egalite, Fraternite placed equality at the heart of French civic identity. Discussion of inegalites is central to DELF B2 essay topics."},
        {type:"mc",q:"Which sentence expresses the idea of low cost correctly?",opts:["Ce manteau est pas cher, je l'achete.","Ce manteau est pas cher de rien.","Pas cher est ce manteau.","Je pas cher ce manteau."],ans:"Ce manteau est pas cher, je l'achete.",hint:"The adverbial phrase comes after a linking verb (etre). The full sentence then uses je + pronom + verbe to act on the result."},
        {type:"fb",opts:["l'urgence","la chance","la reunion","l'entree"],hint:"A feminine noun meaning 'emergency' that also means the hospital emergency room in plural.",s:"C'est {1}! Appelez les secours!",a:["l'urgence"]},
        {type:"mc",q:"Your colleague left early. How do you say 'My colleague left' in French?",opts:["Ma collegue est parti.","Mon collegue est parti.","Le collegue a parti.","Mon collegue est alle."],ans:"Mon collegue est parti.",hint:"Colleague is masculine here. Partir uses etre as its auxiliary in passe compose."},
        {type:"fb",opts:["encore","toujours","souvent","jamais"],hint:"The adverb meaning 'again / still / not yet' depending on context.",s:"Tu veux {1} du cafe? (Would you like more coffee?)",a:["encore"]},
        {type:"mc",q:"Marie is pleased with her new apartment. How does she express this?",opts:["Je suis contents de mon appartement.","Je suis contenti de mon appartement.","Je suis contente de mon appartement.","Je suis content de mon appartement."],ans:"Je suis contente de mon appartement.",hint:"Marie is female. The adjective 'content' adds -e for feminine agreement."},
        {type:"fb",opts:["la mondialisation","l'immigration","la democratie","l'inegalite"],hint:"The feminine noun describing the worldwide economic interconnection process.",s:"La {1} a change le commerce mondial.",a:["la mondialisation"]},
        {type:"match",pairs:[
          {trg:"pas cher",src:"cheap / not expensive"},
          {trg:"l'urgence",src:"the emergency"},
          {trg:"le collegue",src:"the colleague"},
          {trg:"encore",src:"again / still / yet"},
          {trg:"content",src:"happy / pleased"}
        ]},
        {type:"fb",opts:["la democratie","la mondialisation","l'inegalite","l'immigration"],hint:"The civic noun related to people coming into a country to live.",s:"L'{1} est un sujet de debat en France.",a:["l'immigration"]},
        {type:"mc",q:"Which sentence correctly describes growing social inequality?",opts:["Les inegalite social augmentent.","L'inegalites sociales augmentent.","Les inegalites sociales augmente.","Les inegalites sociales augmentent."],ans:"Les inegalites sociales augmentent.",hint:"Check noun-adjective agreement and plural verb conjugation. Both the noun and the verb must reflect a plural subject."},
        {type:"fb",opts:["l'inegalite","la mondialisation","la democratie","l'urgence"],hint:"The political system built on the power of the people (from Greek demos + kratos).",s:"La {1} reste le meilleur systeme politique.",a:["la democratie"]},
        {type:"match",pairs:[
          {trg:"la mondialisation",src:"globalization"},
          {trg:"la democratie",src:"democracy"},
          {trg:"l'immigration",src:"immigration"},
          {trg:"l'inegalite",src:"inequality"}
        ]},
        {type:"mc",q:"A friend says: 'Pas encore!' What does this mean?",opts:["Not yet!","Not again!","Not even!","No more!"],ans:"Not yet!",hint:"Combines the standard French negation pas with the adverb encore in its time-completion sense."},
        {type:"fb",opts:["contente","content","contents","contentes"],hint:"She is pleased with the result. Use the feminine singular form of content.",s:"Elle est tres {1} du resultat.",a:["contente"]},
        {type:"mc",q:"Which three words form the French Republic's motto?",opts:["Egalite, Inegalite, Democratie","Liberte, Egalite, Fraternite","Democratie, Egalite, Liberte","Liberte, Immigration, Fraternite"],ans:"Liberte, Egalite, Fraternite",hint:"France's founding civic slogan connects directly to the vocabulary in this lesson. It appears on public buildings across France."}
  ]}
]};
